class MyQueue:
    def __init__(self):
        self.in_st, self.out_st = [], []
    def _pour(self):
        if not self.out_st:
            while self.in_st:
                self.out_st.append(self.in_st.pop())
    def push(self, x: int) -> None:
        self.in_st.append(x)
    def pop(self) -> int:
        self._pour()
        return self.out_st.pop()
    def peek(self) -> int:
        self._pour()
        return self.out_st[-1]
    def empty(self) -> bool:
        return not self.in_st and not self.out_st

