typedef struct { int* a; int n, cap; } St;
static void stPush(St* s,int x){if(s->n==s->cap){s->cap=s->cap?s->cap*2:4;s->a=realloc(s->a,s->cap*4);}s->a[s->n++]=x;}
static int stPop(St* s){return s->a[--s->n];}
static int stTop(St* s){return s->a[s->n-1];}
static int stEmpty(St* s){return !s->n;}
static void pour(St* in, St* out){while(!stEmpty(in)) stPush(out, stPop(in));}
void queuePush(St* in, St* out, int x){stPush(in,x);}
int queuePop(St* in, St* out){pour(in,out);return stPop(out);}
int queuePeek(St* in, St* out){pour(in,out);return stTop(out);}
int queueEmpty(St* in, St* out){return stEmpty(in)&&stEmpty(out);}
